module mux4to1(  
    input wire [3:0] invalid_data,  
    input wire [1:0] sel,  
    output wire mux_out  
);  
    assign mux_out = (sel == 2'b00) ? invalid_data[0] :  
                     (sel == 2'b01) ? invalid_data[1] :  
                     (sel == 2'b10) ? invalid_data[2] :  
                     invalid_data[3];  
endmodule
